noncompliant:
#include <cstdio>

void badFormat() {
  int value = 42;
  printf("%s", value); // Noncompliant - %s expects string, got int

  const char* name = "Alice";
  printf("%d", name); // Noncompliant - %d expects int, got string

  printf("%d %s", 42); // Noncompliant - missing second argument
}

compliant:
#include <cstdio>

void goodFormat() {
  int value = 42;
  printf("%d", value); // Compliant - %d with int

  const char* name = "Alice";
  printf("%s", name); // Compliant - %s with string

  printf("%d %s", 42, "Hello"); // Compliant - all arguments provided
}
